import React from 'react';
import { View, Text, StyleSheet, Dimensions } from 'react-native';

const steps = ['validée', 'préparation', 'expédiée', 'livrée'];
const statusOrder = { validated: 0, preparation: 1, shipped: 2, delivered: 3 };

const OrderTracker = ({ currentStatus }) => {
  const activeIndex = statusOrder[currentStatus] ?? 0;

  return (
    <View style={styles.container}>
      {steps.map((label, idx) => (
        <View key={label} style={styles.step}>
          <View style={[styles.circle, idx <= activeIndex ? styles.activeCircle : styles.inactiveCircle]}>
            {idx < activeIndex && <Text style={styles.check}>✓</Text>}
            {idx === activeIndex && <Text style={styles.dot}>●</Text>}
            {idx > activeIndex && <Text style={styles.num}>{idx+1}</Text>}
          </View>
          <Text style={[styles.label, idx <= activeIndex && styles.activeLabel]}>{label}</Text>
          {idx < steps.length-1 && <View style={[styles.line, idx < activeIndex ? styles.activeLine : styles.inactiveLine]} />}
        </View>
      ))}
    </View>
  );
};
// styles avec flexDirection row, alignItems center etc.
