async function reorder(orderId: string) {
  try {
    const order = await api.getOrder(orderId); // { items: [{ productId, quantity }] }
    const unavailable: string[] = [];
    for (const item of order.items) {
      const product = await api.checkStock(item.productId);
      if (product.stock >= item.quantity) {
        cartStore.addItem({ ...product, quantity: item.quantity });
      } else {
        unavailable.push(product.name);
      }
    }
    if (unavailable.length > 0) {
      Alert.alert('Stock insuffisant', `Produits indisponibles : ${unavailable.join(', ')}. Les autres ont été ajoutés.`);
    }
    navigation.navigate('CartScreen'); // rediriger vers panier
  } catch (error) {
    Alert.alert('Erreur', 'Impossible de récupérer la commande');
  }
}
